import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.CNG7EpJN.js";const Q=JSON.parse('{"title":"テーブル開放認証","description":"","frontmatter":{"title":"テーブル開放認証"},"headers":[],"relativePath":"tenant/25-table-auth.md","filePath":"tenant/25-table-auth.md"}'),l={name:"tenant/25-table-auth.md"};function i(o,t,h,c,b,n){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_25-テーブル開放認証" tabindex="-1">25. テーブル開放認証 <a class="header-anchor" href="#_25-テーブル開放認証" aria-label="Permalink to &quot;25. テーブル開放認証&quot;">​</a></h1><p>テーブル開放認証は、お客様がテーブルQRから注文する前に、スタッフがその卓を利用可能にする仕組みです。POSLAでは、QRコードを印刷してテーブルに置くだけでは注文できません。スタッフがハンディで <code>QR開放</code> した後、一定時間内にお客様がQRを読むことで注文セッションが開始します。</p><p>この仕組みは、誤注文、いたずら注文、前のお客様のURL再利用、店外からの遠隔注文を防ぐために使います。</p><h2 id="_25-1-用語" tabindex="-1">25-1. 用語 <a class="header-anchor" href="#_25-1-用語" aria-label="Permalink to &quot;25-1. 用語&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用語</th><th>意味</th></tr></thead><tbody><tr><td>テーブルQR</td><td>卓に置く紙のQRコード</td></tr><tr><td>QR開放</td><td>スタッフがその卓を注文可能にする操作</td></tr><tr><td>開放トークン</td><td>QR開放時に発行される一時的な許可情報</td></tr><tr><td>セッション</td><td>そのお客様グループの着席から会計終了までの利用単位</td></tr><tr><td>セッション終了</td><td>会計済み、清掃完了、着席キャンセルなどで利用を終えること</td></tr><tr><td>QR取消</td><td>誤って開放したQR許可を取り消すこと</td></tr><tr><td>QR再発行</td><td>古い開放を取り消し、新しい開放を作ること</td></tr></tbody></table><h2 id="_25-2-基本フロー" tabindex="-1">25-2. 基本フロー <a class="header-anchor" href="#_25-2-基本フロー" aria-label="Permalink to &quot;25-2. 基本フロー&quot;">​</a></h2><ol><li>お客様が来店</li><li>スタッフが空席へ案内</li><li>ハンディの <code>テーブル状況</code> または <code>運用</code> を開く</li><li>対象卓が <code>空き</code> であることを確認</li><li><code>QR開放</code> をタップ</li><li>POSLAが短時間だけ有効な開放トークンを作成</li><li>お客様がテーブルQRを読み込む</li><li>開放トークンが有効なら、テーブルセッションを開始</li><li>お客様はセルフメニューから注文</li><li>会計完了後、セッションは終了</li><li>同じURLを再度開いても、前のお客様の注文画面としては使えない</li></ol><h2 id="_25-3-qr開放の手順" tabindex="-1">25-3. QR開放の手順 <a class="header-anchor" href="#_25-3-qr開放の手順" aria-label="Permalink to &quot;25-3. QR開放の手順&quot;">​</a></h2><ol><li>ハンディを開く</li><li><code>テーブル状況</code> タブを開く</li><li>案内する卓を探す</li><li>卓カードの状態が <code>空き</code> であることを確認</li><li><code>QR開放</code> をタップ</li><li>確認ダイアログを読む</li><li>問題なければOK</li><li>卓カードが <code>QR開放中</code> になる</li><li>お客様にQRを読んでもらう</li></ol><p>運用タブからも同じ操作ができます。壁掛け端末でQR開放中の卓を確認したい場合は、運用タブの <code>QR開放中</code> カードと卓クイック操作を見ます。</p><h2 id="_25-4-qr開放中に表示される情報" tabindex="-1">25-4. QR開放中に表示される情報 <a class="header-anchor" href="#_25-4-qr開放中に表示される情報" aria-label="Permalink to &quot;25-4. QR開放中に表示される情報&quot;">​</a></h2><table tabindex="0"><thead><tr><th>表示</th><th>内容</th></tr></thead><tbody><tr><td>QR読込待ち</td><td>お客様がまだQRを読んでいない</td></tr><tr><td>残り○分</td><td>開放の有効期限までの残り時間</td></tr><tr><td>開放: スタッフ名</td><td>誰が開放したか</td></tr><tr><td>QR取消</td><td>誤開放を取り消す</td></tr><tr><td>QR再発行</td><td>新しい開放に作り直す</td></tr></tbody></table><p><code>開放: スタッフ名</code> は、複数スタッフで営業しているときに、誰が案内した卓か確認するために使います。</p><h2 id="_25-5-qr取消" tabindex="-1">25-5. QR取消 <a class="header-anchor" href="#_25-5-qr取消" aria-label="Permalink to &quot;25-5. QR取消&quot;">​</a></h2><h3 id="_25-5-1-使う場面" tabindex="-1">25-5-1. 使う場面 <a class="header-anchor" href="#_25-5-1-使う場面" aria-label="Permalink to &quot;25-5-1. 使う場面&quot;">​</a></h3><table tabindex="0"><thead><tr><th>場面</th><th>理由</th></tr></thead><tbody><tr><td>間違った卓を開放した</td><td>別のお客様が読んでしまう前に止める</td></tr><tr><td>お客様が席を変えた</td><td>移動前の卓の開放を残さない</td></tr><tr><td>お客様が入店を取りやめた</td><td>開放だけが残るのを防ぐ</td></tr><tr><td>予約席を誤って開放した</td><td>予約客以外が使わないようにする</td></tr></tbody></table><h3 id="_25-5-2-手順" tabindex="-1">25-5-2. 手順 <a class="header-anchor" href="#_25-5-2-手順" aria-label="Permalink to &quot;25-5-2. 手順&quot;">​</a></h3><ol><li><code>テーブル状況</code> または <code>運用</code> を開く</li><li><code>QR開放中</code> の卓を探す</li><li><code>QR取消</code> をタップ</li><li>確認してOK</li><li>卓が空き状態に戻る</li></ol><p>取消後は、まだQRを読み込んでいないお客様は注文画面へ進めません。すでに読み込み済みでセッションが開始している場合は、QR取消ではなく着席キャンセルや会計/清掃の流れで対応します。</p><h2 id="_25-6-qr再発行" tabindex="-1">25-6. QR再発行 <a class="header-anchor" href="#_25-6-qr再発行" aria-label="Permalink to &quot;25-6. QR再発行&quot;">​</a></h2><h3 id="_25-6-1-使う場面" tabindex="-1">25-6-1. 使う場面 <a class="header-anchor" href="#_25-6-1-使う場面" aria-label="Permalink to &quot;25-6-1. 使う場面&quot;">​</a></h3><table tabindex="0"><thead><tr><th>場面</th><th>操作</th></tr></thead><tbody><tr><td>残り時間が少ない</td><td>QR再発行</td></tr><tr><td>スマホの読み込みに失敗した</td><td>QR再発行</td></tr><tr><td>古い開放を使わせたくない</td><td>QR再発行</td></tr><tr><td>スタッフが開放し直したい</td><td>QR再発行</td></tr></tbody></table><h3 id="_25-6-2-手順" tabindex="-1">25-6-2. 手順 <a class="header-anchor" href="#_25-6-2-手順" aria-label="Permalink to &quot;25-6-2. 手順&quot;">​</a></h3><ol><li><code>QR開放中</code> の卓を探す</li><li><code>QR再発行</code> をタップ</li><li>POSLAが古い開放を取り消す</li><li>新しい開放を作る</li><li>残り時間が新しくなる</li><li>お客様に再度QRを読んでもらう</li></ol><h2 id="_25-7-有効期限" tabindex="-1">25-7. 有効期限 <a class="header-anchor" href="#_25-7-有効期限" aria-label="Permalink to &quot;25-7. 有効期限&quot;">​</a></h2><p>QR開放は短時間だけ有効です。読み込み待ちのまま時間切れになった場合、再度 <code>QR開放</code> または <code>QR再発行</code> を行ってください。</p><table tabindex="0"><thead><tr><th>理由</th><th>対応</th></tr></thead><tbody><tr><td>お客様がスマホ操作に時間がかかった</td><td>再発行して案内</td></tr><tr><td>読み込み前に席移動した</td><td>移動元を取消、移動先を開放</td></tr><tr><td>開放後にスタッフが別対応へ行った</td><td>運用タブでQR開放中を確認</td></tr></tbody></table><h2 id="_25-8-セッション開始後の扱い" tabindex="-1">25-8. セッション開始後の扱い <a class="header-anchor" href="#_25-8-セッション開始後の扱い" aria-label="Permalink to &quot;25-8. セッション開始後の扱い&quot;">​</a></h2><p>お客様がQRを読み込んでセッションが開始すると、その卓は <code>着席</code> または <code>食事中</code> として扱われます。</p><table tabindex="0"><thead><tr><th>操作</th><th>説明</th></tr></thead><tbody><tr><td>注文</td><td>スタッフがハンディで追加注文</td></tr><tr><td>QR表示</td><td>お客様向け/個別QRを再表示</td></tr><tr><td>メモ</td><td>アレルギーや接客メモを保存</td></tr><tr><td>人数変更</td><td>来店人数の修正</td></tr><tr><td>席移動</td><td>セッションと注文を別卓へ移動</td></tr><tr><td>会計呼び出し</td><td>会計待ちにする</td></tr></tbody></table><h2 id="_25-9-会計完了後のurl再利用防止" tabindex="-1">25-9. 会計完了後のURL再利用防止 <a class="header-anchor" href="#_25-9-会計完了後のurl再利用防止" aria-label="Permalink to &quot;25-9. 会計完了後のURL再利用防止&quot;">​</a></h2><p>会計が完了すると、対象セッションは終了します。前のお客様がスマホの履歴や同じURLから再度アクセスしても、そのセッションの注文・履歴・会計情報へ進めないように制御されます。</p><p>店舗側で必ず行うこと:</p><ol><li>レジで会計を完了する</li><li>テーブル状態が会計済み/清掃待ち/終了済みに進んだことを確認</li><li>清掃完了後、次のお客様を案内する</li><li>次のお客様には必ず新しくQR開放する</li></ol><div class="warning custom-block"><p class="custom-block-title">前のお客様の画面が残っていると言われた場合</p><p>まず会計が完了しているか、テーブルセッションが終了しているかを確認してください。会計完了前にお客様がブラウザ履歴を開いた場合は、まだ同じセッションとして扱われます。会計完了後も見える場合は、店舗・卓番号・発生時刻を控えてPOSLAサポートへ連絡してください。</p></div><h2 id="_25-10-席移動とqr開放" tabindex="-1">25-10. 席移動とQR開放 <a class="header-anchor" href="#_25-10-席移動とqr開放" aria-label="Permalink to &quot;25-10. 席移動とQR開放&quot;">​</a></h2><p>席移動では、セッション、未会計注文、QR情報、メモ、呼び出し、サブセッションをまとめて移します。</p><table tabindex="0"><thead><tr><th>状況</th><th>操作</th></tr></thead><tbody><tr><td>移動元が着席中</td><td><code>席移動</code> で空席へ移す</td></tr><tr><td>移動先がQR開放中</td><td>先に移動先のQR取消、または別卓を選ぶ</td></tr><tr><td>移動元だけQR開放中</td><td>QR取消してから移動先を開放</td></tr><tr><td>移動後にセルフ注文を続ける</td><td>移動先でQR表示または必要に応じて再案内</td></tr></tbody></table><h2 id="_25-11-予約来店との関係" tabindex="-1">25-11. 予約来店との関係 <a class="header-anchor" href="#_25-11-予約来店との関係" aria-label="Permalink to &quot;25-11. 予約来店との関係&quot;">​</a></h2><p>予約客が来店した場合は、予約タブまたはテーブル状況から操作します。</p><table tabindex="0"><thead><tr><th>操作</th><th>使う場面</th></tr></thead><tbody><tr><td>予約着席</td><td>スタッフが予約客を直接着席済みにする</td></tr><tr><td>QR開放</td><td>予約客にセルフ注文してもらう</td></tr><tr><td>no-show</td><td>予約客が来なかった</td></tr></tbody></table><p>予約席を誤って別のお客様にQR開放しないよう、テーブルカードの予約表示とメモを確認してください。</p><h2 id="_25-12-トラブルシューティング" tabindex="-1">25-12. トラブルシューティング <a class="header-anchor" href="#_25-12-トラブルシューティング" aria-label="Permalink to &quot;25-12. トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>お客様がQRを読んでも進めない</td><td>QR未開放、期限切れ、通信不安定</td><td>ハンディでQR開放中か確認し、必要なら再発行</td></tr><tr><td>別卓の画面が開く</td><td>紙QRの貼り間違い、卓選択ミス</td><td>QR紙と卓番号を確認し、誤開放なら取消</td></tr><tr><td>QR開放中が残っている</td><td>お客様が読まずに時間が経過</td><td>読む予定がなければ取消</td></tr><tr><td>前のお客様の情報が見える</td><td>会計/終了処理漏れの可能性</td><td>レジ会計完了、清掃完了、セッション終了を確認</td></tr><tr><td>予約客が注文できない</td><td>予約卓が未開放、別卓に案内</td><td>予約タブで対象予約と卓を確認し、QR開放</td></tr><tr><td>席移動後に注文が旧卓に見える</td><td>画面が古い</td><td>運用タブまたはテーブル状況を更新</td></tr><tr><td>QR再発行後も進めない</td><td>端末側キャッシュ、通信不安定</td><td>ブラウザを閉じて再読込、Wi-Fi確認</td></tr></tbody></table><h2 id="_25-13-店舗ルールとして決めておくこと" tabindex="-1">25-13. 店舗ルールとして決めておくこと <a class="header-anchor" href="#_25-13-店舗ルールとして決めておくこと" aria-label="Permalink to &quot;25-13. 店舗ルールとして決めておくこと&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ルール</th><th>推奨</th></tr></thead><tbody><tr><td>QR開放担当</td><td>案内したスタッフが開放する</td></tr><tr><td>QR開放後の声かけ</td><td>2分程度で読めているか確認</td></tr><tr><td>誤開放時</td><td>気づいたスタッフが即取消</td></tr><tr><td>席移動時</td><td>移動前に卓番号を復唱し、移動後に運用タブで確認</td></tr><tr><td>会計後</td><td>レジ担当が終了状態を確認し、ホールが清掃完了</td></tr><tr><td>共有端末</td><td>壁掛け端末は運用タブ、音ONで使う</td></tr></tbody></table>',46)])])}const s=d(l,[["render",i]]);export{Q as __pageData,s as default};
